package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testReadReturnsCharAndUpdatesLastCharWithoutLineIncrement() throws IOException {
        // Setup to return a character other than \n (e.g. 'A')
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn((int) 'A').when(spyReader).read();

        // actually call super.read()
        // but since super.read() is BufferedReader.read(), 
        // we cannot mock it directly,
        // so in this scenario, we use reflection to override lastChar and lineCounter to test logic

        // To test the read method, we need to mock super.read().
        // We'll create a subclass that overrides read() for test purposes

        ExtendedBufferedReader br = new ExtendedBufferedReader(mockReader) {
            int callCount = 0;
            @Override
            public int read() throws IOException {
                callCount++;
                if (callCount == 1) {
                    return 'A'; // Not a newline
                } else if (callCount == 2) {
                    return '\n'; // Newline
                } else if (callCount == 3) {
                    return ExtendedBufferedReader.END_OF_STREAM; // End of stream
                }
                return ExtendedBufferedReader.END_OF_STREAM;
            }

            public int testRead() throws IOException {
                return super.read();
            }
        };

        // Since we can't mock super.read() directly, we test the actual read() logic by calling the real method.

        // Because the focal method calls super.read(), which in BufferedReader reads from the Reader,
        // instead, we override read() in subclass to control the values returned.

        // First call with 'A'
        int result1 = br.read();
        assertEquals('A', result1);

        // lineCounter should not have incremented
        int lineNumberField1 = getPrivateIntField(br, "lineCounter");
        assertEquals(0, lineNumberField1);

        // lastChar should be 'A'
        int lastCharField1 = getPrivateIntField(br, "lastChar");
        assertEquals('A', lastCharField1);

        // Second call with '\n'
        int result2 = br.read();
        assertEquals('\n', result2);

        int lineNumberField2 = getPrivateIntField(br, "lineCounter");
        assertEquals(1, lineNumberField2);

        int lastCharField2 = getPrivateIntField(br, "lastChar");
        assertEquals('\n', lastCharField2);

        // Third call with END_OF_STREAM
        int result3 = br.read();
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result3);

        int lineNumberField3 = getPrivateIntField(br, "lineCounter");
        // lineCounter should remain the same
        assertEquals(1, lineNumberField3);

        int lastCharField3 = getPrivateIntField(br, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastCharField3);
    }

    // helper method for reflection access on private int fields
    private int getPrivateIntField(Object instance, String fieldName) {
        try {
            java.lang.reflect.Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(instance);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
